var e=JSON.parse(`[{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"따라서 관리국은 리플레이서 사태와 같은 범세계적 재난에\\n대처하고자, 태스크포스 간의 긴밀한 연대를 권장하려 합니다.","JPN":"したがって、管理局はリプレイサー事件のような世界規模の災害に\\n対処するべく、タスクフォース同士の緊密な連携を推奨します。","ENG":"Therefore, the Administration recommends a seamless coalition across all TASKFORCES\\nin order to effectively respond to global crises such as the Replacer Incident.","TWN":"因此管理局爲了應對像克隆集團事件一樣的全球性災難，\\n鼓勵特遣勢力之間的緊密合作。"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"subtitle","speaker":null,"text":{"KOREA":"이러한 방침에 따라, 관리국 인증을 받은 조직 간의\\n연합체 구성 초안을 전달드리오니......","JPN":"このような方針に基づき、管理局の認証を受けた組織間の\\n連合体構成の草案をお届けしますので……","ENG":"Based on this new policy, please find enclosed a draft\\nof the coalition proposal between Administration-approved organizations...","TWN":"因應此方針，而提出在獲得管理局認可的組織之間組成聯盟的草案…"},"stage":{"bg":"MAINSTREAM_000008","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"어머, 부사장님. 아직 남아 계셨네요.","JPN":"あら、副社長。まだ残業されてたんですね。","ENG":"Oh, Vice President. You're still here.","TWN":"哎呀，副總，您還沒走啊。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"네. 관리국에서 공문이 왔더군요.","JPN":"ええ。管理局から文書が届きまして。","ENG":"Yes. The Administration sent us an official memo.","TWN":"是的，因為管理局發來了公文。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"금방 끝날 테니 먼저 퇴근하세요. 요즘 제시간에 퇴근한 적이 없는 것 같던데.","JPN":"すぐに済ませますので、先に上がってください。\\n最近は定時に帰れていないでしょう？","ENG":"I won't be long. Please go ahead and go home. I've hardly seen you leave work on time lately.","TWN":"我馬上就好了，妳先下班吧。妳不是已經很久沒有準時下班了嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"후훗. 그러는 부사장님께선 예전이나 지금이나 늦게까지 계시잖아요.","JPN":"ふふっ。そういう副社長は今も昔も変わらず遅くまでおられますよね。","ENG":"Heh heh. But you've always been burning the midnight oil here.","TWN":"呵呵，副總從以前到現在，不也都留得很晚嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"회사에 여유가 생겼는데 가끔은 개인 시간도 가지셔야죠.","JPN":"会社も軌道に乗ってきたことですし、\\nたまにはプライベートの時間を過ごされてもいいと思いますよ。","ENG":"You should take some personal time. The company is doing well these days.","TWN":"公司情況也好轉了，您偶爾也該享受一下個人的時間吧。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"전 얼마 전에 고등학교 동창들을 만났는데, 꼭 그 때로 돌아간 기분이더라고요.","JPN":"この前、高校の同窓会に行ってきたんですが、\\nまるで昔に戻ったような気分になりました。","ENG":"As for me, I met a few of my classmates from high school recently and it felt like the good old times again.","TWN":"我前幾天和高中同學聚會，感覺就像回到我的少女時代一樣呢！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"부사장님도 오랜만에 젊은 시절 친구 분들과 만나서 기분전환을 해 보시는 건 어떠세요?","JPN":"副社長も久しぶりに若い頃の友人にお会いして、\\n気分転換でもされてみてはどうでしょう？","ENG":"Why don't you also spend some time catching up with old friends? It can be quite refreshing.","TWN":"副總不如也久違地去見見年輕時候的朋友，稍微轉換一下心情如何？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"아......!","JPN":"あっ……！","ENG":"Oh...","TWN":"啊……！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"저기, 그러니까 부사장님이 나이 드셨다는 뜻은 아니었어요. 제 말은......","JPN":"えっと、その、副社長がお年を召されたと\\n言いたかったわけじゃないんです。私が言いたかったのは……","ENG":"I didn't mean to say that you're old... What I meant was...","TWN":"那個，我不是說您老了，我是說……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"괜찮아요.","JPN":"気にしなくて大丈夫ですよ。","ENG":"It's okay.","TWN":"沒關係。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그리고...... 제 예전 친구들은 대부분 연락이 끊겨서요.","JPN":"ただ……昔の友人とはほとんど連絡が途絶えてしまったんです。","ENG":"Besides... I've lost touch with most of my old friends.","TWN":"還有……我和我以前的朋友幾乎都沒有聯絡了。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"한자리에 모이기는 조금 어렵겠어요.","JPN":"一堂に会するなんてことは、ちょっと難しいかもしれません。","ENG":"So I'm afraid it'll be difficult to catch up with many of them.","TWN":"要聚在一起應該有點困難吧。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"그러셨군요...... 제가 괜한 말을 꺼냈네요.","JPN":"そうだったんですね……私、余計なことを言ってしまいました。","ENG":"I see... Sorry I brought it up.","TWN":"原來如此……是我多嘴了。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"후훗. 아뇨. 걱정해 줘서 고마워요.","JPN":"ふふっ。いえ、気にかけてくれてありがとうございます。","ENG":"Hah hah. It's quite alright. Thank you for your concern.","TWN":"呵呵，不會，謝謝妳的關心。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그나저나 이렇게 여유 부리다간 다음 열차 놓칠 텐데, 괜찮겠어요?","JPN":"それはそうと、このままだと次の電車に\\n間に合いませんが大丈夫ですか？","ENG":"By the way, shouldn't you get going? You're going to miss your train.","TWN":"不過，妳還有時間跟我哈拉嗎？下一班車要到了吧?沒關係嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"아, 그렇네요! 내 정신 좀 봐!","JPN":"あっ、そうでした！　私ったらついうっかり！","ENG":"Oh, you're right! I completely forgot!","TWN":"啊，對喔！我差點忘了！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"먼저 가 보겠습니다. 비도 오는데 일찍 들어가세요, 부사장님.","JPN":"先に上がらせていただきます。雨も降っていますし、\\n副社長も早く上がってくださいね。","ENG":"Well, I'd better get going then. Don't stay out too late, ma'am. It's raining.","TWN":"那我先走了，副總。您也不要弄太晚，外面下著雨呢。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L40_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"후우...... 또 눈이 말썽이네.","JPN":"ふう……また目が疼いてきたわ。","ENG":"*Sigh* The eye's acting up again.","TWN":"唉……眼睛又開始痛了。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그런데 벌써 막차 시간인가?","JPN":"それにしても、もう終電の時間？","ENG":"Anyway, is it almost time for the last ride home already?","TWN":"話說回來，已經到了末班車的時間了嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"남는 김에 밀린 결재도 처리하려 했더니......","JPN":"どうせ残業するなら溜まった書類も片付けたかったのだけど……","ENG":"I was going to finish catching up on the paperwork...","TWN":"本來想要留下來，順便把擱置的帳目都結清的……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"어쩔 수 없지. 나머지는 내일 끝내야겠어.","JPN":"仕方ないわね。残りは明日終わらせることにしましょう。","ENG":"Oh well. I guess I'll just have to finish the rest tomorrow.","TWN":"沒辦法了，剩下的就明天再做吧。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>ADC-G1 도시관리국이 침식재난 경계령을 발령합니다.</color>","JPN":"<color=#ffd34c>ADC-G1都市管理局が侵食災害警報を発令します。</color>","ENG":"<color=#ffd34c>ADC-G1 City Management has issued a Corruption disaster warning.</color>","TWN":"<color=#ffd34c>ADC-G1城市管理局發佈侵蝕災難警戒令。</color>"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>방금 전, 시가지에서 일시적인 침식파 밀도 증가가 감지되었습니다.</color>","JPN":"<color=#ffd34c>先程市街地にて、一時的な侵食波密度の増加を感知しました。</color>","ENG":"<color=#ffd34c>A temporary increase in Corruption Ray levels has just been detected in the city.</color>","TWN":"<color=#ffd34c>剛才，我們偵測到市區的侵蝕波密度有短暫增加的現象。</color>"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>시민 여러분은 안전이 확인되기 전까지 실외 활동을 삼가하여 주시기 바랍니다.</color>","JPN":"<color=#ffd34c>市民の皆様におかれましては、安全が確認されるまで外出を控えていただくようお願いします。</color>","ENG":"<color=#ffd34c>All citizens are advised to stay inside and avoid outdoor activities until the situation is under control.</color>","TWN":"<color=#ffd34c>在確認安全之前，請各位市民儘量避免戶外活動。</color>"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"오늘만 벌써 몇 번째인지 원...... 요즘 들어 더 심해지는 것 같네.","JPN":"今日だけで何度目かしら……\\nこの頃、ますます増えてきてる気がするわ。","ENG":"How many times is that already today? It seems to be getting worse these days.","TWN":"今天這都是第幾次了……最近變得越來越嚴重了。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_SIREN"},{"id":"L7_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"응? 이 시간에 누구 전화지?","JPN":"電話……？　こんな時間に誰かしら？","ENG":"Huh? Who could be calling at this hour?","TWN":"嗯？這個時間會有誰打電話過來？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_UI_BUTTON_SELECT"},{"id":"L9_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"네. 코핀 컴퍼니의 이수연 부사장입니다.","JPN":"はい。コフィンカンパニー副社長、カナミ・キズナです。","ENG":"Hello. This is Lee Sooyeon, vice president of the Coffin Company.","TWN":"你好，我是科芬公司的副總李秀妍。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ARTIL_ADMIN_QM_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"여보세요? 누구시죠?","JPN":"もしもし？　どちら様？","ENG":"Hello? Who's this?","TWN":"喂？你是哪位？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ARTIL_ADMIN_QM_NULL","text":{"KOREA":"나다. 오랜만이군.","JPN":"私だ。久しぶりだな。","ENG":"It's me. Long time no... talk.","TWN":"是我，好久不見了。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......죄송하지만 제 쪽에서는 등록되지 않은 번호로 나오는군요.","JPN":"……申し訳ございませんが、私の方には未登録番号と表示されています。","ENG":"I'm sorry, but your number isn't registered on my phonebook.","TWN":"……不好意思，我這邊顯示為未登記的號碼。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"의뢰를 원하는 클라이언트시면 성함을 말씀해 주시겠습니까?","JPN":"依頼をご希望のクライアントの方でしたら、お名前を教えていただけますか？","ENG":"Could you please tell me your name if you're a client seeking our services?","TWN":"如果您是需要委託的客戶，可以請您告訴我您的姓名嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ARTIL_ADMIN_QM_NULL","text":{"KOREA":"클라이언트?","JPN":"クライアント？","ENG":"Client?","TWN":"客戶？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ARTIL_ADMIN_QM_NULL","text":{"KOREA":"뭔가 착각했나 보군. 설마 내 목소리를 잊어 버렸나?","JPN":"何か勘違いしてるようだな。まさか、私の声を忘れてしまったか？","ENG":"You must be mistaken. Have you forgotten my voice already?","TWN":"妳好像搞錯了，難道妳不記得我的聲音了？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하아......","JPN":"ふぅ……","ENG":"*Sigh*","TWN":"哈啊……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"보이스 피싱이라면 낮에 다시 거세요.","JPN":"オレオレ詐欺なら就業時間におかけ直しください。","ENG":"If this is a phishing scam, you should try back during the day.","TWN":"如果是詐騙電話，請妳明天上午再打來吧。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그럼 이런 낡은 수법에 속아 줄 멍청한 직원도 한 명쯤은 있을 겁니다.","JPN":"そんな古い手口に引っかかってくれる\\n間抜けな社員も一人くらいいるはずです。","ENG":"Some of my staff might be actually dumb enough to fall for this old trick.","TWN":"那樣妳這老套的手法或許還能騙到一兩個笨員工。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아쉽지만 전 급전이 필요할 만한 가족도, 친구도 없어서 상대해 드리기 어렵겠군요.","JPN":"あいにく私にはギフトカードをねだるような家族も友人も\\nおりませんので、要望にはお応えいたしかねます。","ENG":"As for me, I regrettably don't have any friends or family that might urgently need money from me.","TWN":"很遺憾的，我這邊沒有急需用錢的家人或朋友，要配合妳有點困難呢。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ARTIL_ADMIN_QM_NULL","text":{"KOREA":"......실망이군.","JPN":"……ガッカリだな。","ENG":"How disappointing.","TWN":"……真讓人失望。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ARTIL_ADMIN_QM_NULL","text":{"KOREA":"아무리 시간이 흘렀다지만 옛 전우의 목소리까지 잊어 버렸나.","JPN":"いくら時間が経ったとはいえ、かつての戦友の声まで忘れたのか。","ENG":"Granted, it's been many years... but how could you forget the voice of your comrade?","TWN":"雖然已經過了很久，但沒想到妳連昔日戰友的聲音都忘了。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ARTIL_ADMIN_QM_NULL","text":{"KOREA":"내가 아는 펜릴 전대의 이수연답지 않군.","JPN":"私の知るフェンリル戦隊のカナミ・キズナとは思えん。","ENG":"That's not like the Lee Sooyeon of the Fenrir Division that I knew.","TWN":"這可不像是我認識的芬里爾戰隊李秀妍。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"당신, 그 이야기는 어디서 들었지?","JPN":"あなた、それをどこで聞いたの？","ENG":"Where did you hear about that?","TWN":"妳這是在哪裡聽到的？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"잠깐, 그 말투......","JPN":"待って。その喋り方は……","ENG":"Hang on, the way you speak...","TWN":"等等，妳這語氣……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"설마...... 류드밀라? 메이즈 전대의?","JPN":"まさか……リュドミラ？　メイズ戦隊の？","ENG":"Could it be... Lyudmila? Of the Maze Division?","TWN":"難道是……盧德米拉？梅茲戰隊的？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"......그래, 나다. 기억해 주다니 고맙군.","JPN":"……ああ、私だ。思い出してもらえて何よりだ。","ENG":"Yes, it's me. It's nice to know that you remember me.","TWN":"……對，是我。妳竟然還記得我，還真是感人呢！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L35_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"살아 있었다고? 대체 어떻게......","JPN":"生きていた、ですって？　いったいどうやって……","ENG":"You're alive? But how?","TWN":"妳還活著？怎麼會……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아니, 자세한 건 만나서 얘기하자.","JPN":"いえ、詳しいことは会って話しましょう。","ENG":"No, we should talk about the details in person.","TWN":"不，詳細的事情還是見面再說吧。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"지금 어딘지 말해. 당장 데리러 갈 테니까.","JPN":"今どこにいるか教えて。すぐ迎えに行くわ。","ENG":"Tell me where you are now. I'll go pick you up right away.","TWN":"妳現在在哪裡，我馬上去接妳。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"자, 따듯한 커피야. 마시면서 몸 좀 녹여.","JPN":"ほら、ホットコーヒーよ。まずは飲んで温まるといいわ。","ENG":"Here's some warm coffee. Drink some to warm yourself.","TWN":"來，喝一杯熱咖啡吧，暖暖身子。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L42_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"고맙다. 갑자기 비가 오는 바람에 피하지도 못했어.","JPN":"いただくとしよう。急に降り出したものでな。\\n私としたことが濡れてしまった。","ENG":"Thank you. It just rained so suddenly that I couldn't take shelter.","TWN":"謝謝，突然下起雨來，我來不及躲雨。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L44_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그나저나 직접 보고도 믿기지 않는군.","JPN":"しかし、実際に見てもなお信じがたいな。","ENG":"In any case, I can hardly believe what I'm seeing.","TWN":"不過就算親眼看到，還真是令人不敢相信。。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그 하늘 높은 줄 모르고 설치던 꼬마가 지금은 정장이 어울리는 부사장님이라니.","JPN":"あの天下に怖いものなしだった大暴れ娘が、\\n今はスーツがお似合いの副社長様か。","ENG":"That cheeky brat has managed to become a Vice President. The suit actually looks good on you.","TWN":"沒想到當年不知天高地厚的小丫頭，現在已經是位西裝筆挺的副總了。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"믿기지 않기는 나도 마찬가지야.","JPN":"信じがたいのは私も同じよ。","ENG":"I find your presence equally unbelievable.","TWN":"我也一樣不敢相信。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그 지옥에서...... 대체 어떻게 살아남은 거지?","JPN":"あの地獄から……いったいどうやって生き延びたの？","ENG":"You came back from that hell... How did you manage to survive?","TWN":"妳到底是怎麼從那個……地獄活下來的？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"구 관리국이 망한 지 20년이나 지나서 나타난 건 또 뭐고?","JPN":"旧管理局の崩壊から20年も経って現れたのはどうして？","ENG":"And why did you show up 20 years after the fall of the Old Administration?","TWN":"而且為什麼在舊管理局瓦解20多年後才出現？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"구 관리국?","JPN":"旧管理局？","ENG":"Old Administration?","TWN":"舊管理局？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"지금은...... 그렇게 부르나?","JPN":"今は……そう呼ばれてるのか？","ENG":"Is that... what they call it these days?","TWN":"現在……這麼叫它的嗎？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"흥미롭군. 꼭 다른 세상 이야기라도 하는 것 같아.","JPN":"興味深いな。まるで別世界の話でも聞かされてる気分だ。","ENG":"Interesting. It sounds as if we're talking about an entirely different world.","TWN":"有意思，好像在說另一個世界的事情一樣。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"나 역시 지금 세상에 대해 궁금한 점이 많아.","JPN":"私の方も今の世の中について聞きたいことは山ほどある。","ENG":"I too have many questions about the world in its current state.","TWN":"關於現在這個世界，我也有很多問題。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"하지만 도움을 청하러 온 이상, 내 이야기부터 해야 하겠지.","JPN":"しかし助けを求めに来た以上、\\nまずは私の身の上について話をさせてもらおう。","ENG":"But since I'm here to ask for your help, I suppose I'm obliged to answer yours first.","TWN":"但既然我是來尋求幫助的，我就得先說我的事情才行。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"괜찮으면 커피 한 잔 더 부탁하지. 뜨거운 걸로.","JPN":"すまないがコーヒーをもう一杯頼めるか？　同じくホットで。","ENG":"I'd like another cup of coffee if you don't mind. Please make it steaming hot,","TWN":"可以的話再給我來一杯咖啡，要熱的。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"......이야기가 길어질 것 같으니까.","JPN":"……長い話になりそうだからな。","ENG":"because this is going to be a long story.","TWN":"……因為故事會很長。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};